<template><div class="message" :class="item.sender"><div class="message-row"><div class="message-avatar"><img v-if="item.senderAvatar" :src="item.senderAvatar" alt=""/><span v-else>{{initial}}</span></div><div class="message-body"><strong>{{item.senderName||fallbackName}}</strong><div class="bubble">{{item.content}}</div><small>{{item.read?'已读':'未读'}}</small></div></div></div></template><script setup lang="ts">import{computed}from'vue';const props=defineProps<{item:any}>();const fallbackName=computed(()=>props.item.sender==='seller'?'卖家':'买家');const initial=computed(()=>(props.item.senderName||fallbackName.value).slice(0,1))</script>
